    clients map[chan SSEEvent]struct{}
}

// Subscribe creates buffered channel (64 slot buffer) for a client
ch := make(chan SSEEvent, 64)
b.clients[ch] = struct{}{}

// Send fans out to all clients (non-blocking for slow clients)
for ch := range b.clients {
